    46→// Converts the XdsTp resource name to its wildcard equivalent.
    47→// Must only be called on XdsTp resource names.
    48→std::string convertToWildcard(const std::string& resource_name) {
    49→  ASSERT(XdsResourceIdentifier::hasXdsTpScheme(resource_name));
