185→void DeltaSubscriptionState::handleGoodResponse(
   186→    const envoy::service::discovery::v3::DeltaDiscoveryResponse& message) {
   187→  absl::flat_hash_set<std::string> names_added_removed;
   188→  Protobuf::RepeatedPtrField<envoy::service::discovery::v3::Resource> non_heartbeat_resources;
   189→  for (const auto& resource : message.resources()) {
   190→    if (!names_added_removed.insert(resource.name()).second) {
   191→      throw EnvoyException(
   192→          fmt::format("duplicate name {} found among added/updated resources", resource.name()));
   193→    }
   194→    if (isHeartbeatResponse(resource)) {
   195→      continue;
   196→    }
   197→    non_heartbeat_resources.Add()->CopyFrom(resource);
   198→    // DeltaDiscoveryResponses for unresolved aliases don't contain an actual resource
   199→    if (!resource.has_resource() && resource.aliases_size() > 0) {
   200→      continue;
   201→    }
   202→    if (message.type_url() != resource.resource().type_url()) {
   203→      throw EnvoyException(fmt::format("type URL {} embedded in an individual Any does not match "
   204→                                       "the message-wide type URL {} in DeltaDiscoveryResponse {}",
   205→                                       resource.resource().type_url(), message.type_url(),
   206→                                       message.DebugString()));
   207→    }
   208→  }
   209→  for (const auto& name : message.removed_resources()) {
   210→    if (!names_added_removed.insert(name).second) {
   211→      throw EnvoyException(
   212→          fmt::format("duplicate name {} found in the union of added+removed resources", name));
   213→    }
   214→  }
   215→
   216→  watch_map_.onConfigUpdate(non_heartbeat_resources, message.removed_resources(),
   217→                            message.system_version_info());
   218→
   219→  // Processing point when resources are successfully ingested.
   220→  if (xds_config_tracker_.has_value()) {
   221→    xds_config_tracker_->onConfigAccepted(message.type_url(), non_heartbeat_resources,
   222→                                          message.removed_resources());
   223→  }
   224→
   225→  {
   226→    const auto scoped_update = ttl_.scopedTtlUpdate();
   227→    if (requested_resource_state_.contains(Wildcard)) {
   228→      for (const auto& resource : message.resources()) {
   229→        addResourceStateFromServer(resource);
   230→      }
   231→    } else {
   232→      // We are not subscribed to wildcard, so we only take resources that we explicitly requested
   233→      // and ignore the others.
   234→      for (const auto& resource : message.resources()) {
   235→        if (requested_resource_state_.contains(resource.name())) {
   236→          addResourceStateFromServer(resource);
   237→        }
   238→      }
   239→    }
   240→  }
   241→
   242→  // If a resource is gone, there is no longer a meaningful version for it that makes sense to
   243→  // provide to the server upon stream reconnect: either it will continue to not exist, in which
   244→  // case saying nothing is fine, or the server will bring back something new, which we should
   245→  // receive regardless (which is the logic that not specifying a version will get you).
   246→  //
   247→  // So, leave the version map entry present but blank if we are still interested in the resource.
   248→  // It will be left out of initial_resource_versions messages, but will remind us to explicitly
   249→  // tell the server "I'm cancelling my subscription" when we lose interest. In case of resources
   250→  // received as a part of the wildcard subscription or resources we already lost interest in, we
   251→  // just drop them.
   252→  for (const auto& resource_name : message.removed_resources()) {
   253→    if (auto maybe_resource = getRequestedResourceState(resource_name);
   254→        maybe_resource.has_value()) {
   255→      maybe_resource->setAsWaitingForServer();
   256→    } else if (const auto erased_count = ambiguous_resource_state_.erase(resource_name);
   257→               erased_count == 0) {
   258→      wildcard_resource_state_.erase(resource_name);
   259→    }
   260→  }
   261→  ENVOY_LOG(debug, "Delta config for {} accepted with {} resources added, {} removed", type_url_,
   262→            message.resources().size(), message.removed_resources().size());
